actions
(
    {
        name    c0;
        type    cellSet;
        action  new;
        source  boxToCell;
        sourceInfo
        {
            box (0.5 0 -0.1) (0.625 0.375 1.1);
        }
    }

    {
        name    obstacle;
        type    cellZoneSet;
        action  new;
        source  setToCellZone;
